-- lesson-1-task1: Task 1: Initialize System Power Using the AXP202
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Configure the power management system so the watch can boot and supply power to required peripherals."}, {"title": "Implementation Guidance", "content": "- Use the `AXP20X.h` library to control the AXP202 power management IC\n- Establish I2C communication with the AXP202\n- Identify required power rails using the schematic\n- Enable the appropriate LDOs to power the system and display\n- Review example code provided by the AXP20X library\n\n```cpp\n#include <AXP20X.h>\n\nAXP20X axp;\n\nbool initPower() {\n    // Initialize I2C communication with AXP202\n    if (axp.begin(Wire, AXP202_SLAVE_ADDRESS) != AXP_PASS) {\n        return false;\n    }\n    \n    // Enable power for display backlight (LDO2)\n    axp.setPowerOutPut(AXP202_LDO2, AXP202_ON);\n    \n    // Enable power for display (LDO3)\n    axp.setPowerOutPut(AXP202_LDO3, AXP202_ON);\n    \n    return true;\n}\n```"}, {"title": "Required Files", "content": "- `power.h` - Header file with power function declarations\n- `power.cpp` - Implementation of power initialization and control"}], "key_points": ["Use AXP20X library for power management", "Check schematic for required power rails", "Enable LDOs for display and other peripherals"], "resources": []}' WHERE id = 'lesson-1-task1';

-- lesson-1-task2: Task 2: Display Text Using TFT_eSPI
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Verify that the display is functioning by printing text after system boot."}, {"title": "Implementation Guidance", "content": "- Use the `TFT_eSPI` library to interface with the display\n- Initialize the display before writing any graphics\n- Print the text \"Hello World\" after boot\n- Experiment with text color, background color, and position\n\n```cpp\n#include <TFT_eSPI.h>\n\nTFT_eSPI tft = TFT_eSPI();\n\nvoid initDisplay() {\n    tft.init();\n    tft.setRotation(0);\n    tft.fillScreen(TFT_BLACK);\n    \n    // Set text properties\n    tft.setTextColor(TFT_WHITE, TFT_BLACK);\n    tft.setTextSize(2);\n    \n    // Print text at position (10, 10)\n    tft.setCursor(10, 10);\n    tft.println(\"Hello World\");\n}\n```"}, {"title": "Required Files", "content": "- `display.h` - Header file with display function declarations\n- `display.cpp` - Implementation of display initialization and graphics output"}], "key_points": ["Initialize display before writing graphics", "Use setTextColor for foreground and background", "setCursor positions text on screen"], "resources": []}' WHERE id = 'lesson-1-task2';

-- lesson-1-task3: Task 3: Power Button Interrupt
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Use a hardware interrupt to toggle the display on and off using the side button."}, {"title": "Implementation Guidance", "content": "- The side button is connected to the interrupt pin of the AXP202\n- Identify the correct interrupt pin using the schematic\n- Refer to the Interrupts and ISRs section for proper ISR structure\n- Keep the ISR minimal and defer logic to the main program or task\n- Use a shared flag or notification to toggle display state\n\n```cpp\n#define AXP202_INT_PIN 35\n\nvolatile bool axpInterrupt = false;\nbool displayOn = true;\n\nvoid IRAM_ATTR axpISR() {\n    axpInterrupt = true;\n}\n\nvoid setup() {\n    // Configure interrupt pin\n    pinMode(AXP202_INT_PIN, INPUT_PULLUP);\n    attachInterrupt(digitalPinToInterrupt(AXP202_INT_PIN), axpISR, FALLING);\n    \n    // Enable button press interrupt in AXP202\n    axp.enableIRQ(AXP202_PEK_SHORTPRESS_IRQ, true);\n    axp.clearIRQ();\n}\n\nvoid loop() {\n    if (axpInterrupt) {\n        axpInterrupt = false;\n        \n        axp.readIRQ();\n        if (axp.isPEKShortPressIRQ()) {\n            displayOn = !displayOn;\n            if (displayOn) {\n                turnDisplayOn();\n            } else {\n                turnDisplayOff();\n            }\n        }\n        axp.clearIRQ();\n    }\n}\n```"}, {"title": "Required Files", "content": "- `power.h` and `power.cpp` - Handles AXP202 power initialization and control\n- `display.h` and `display.cpp` - Handles display initialization and graphics output\n- `main.cpp` - Coordinates system startup and high-level behavior"}], "key_points": ["Use IRAM_ATTR for interrupt handler", "Keep ISR minimal - set flag only", "Clear AXP202 IRQ after handling", "Defer display toggle to main loop"], "resources": []}' WHERE id = 'lesson-1-task3';

-- ============================================================================
-- MODULE 2: Time and Date
-- ============================================================================

-- lesson-2-task1: Task 1: RTC Storage and Retrieval
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Use the PCF8563 real-time clock to store and retrieve the current date and time."}, {"title": "Requirements", "content": "You must design functions in `mytime.h` and `mytime.c` that allow the system to write time data to the RTC and read it back. These functions should then be used from `main.cpp`.\n\n**Time Format:**\n- 24-hour format (00:00 to 23:59)\n- Date includes month, day, and year\n\n**Important:** All firmware for this task must be written in C and use only the libraries provided in the repository. In particular, you should rely on `driver/i2c.h` and `esp_err.h` for low-level communication and error handling."}, {"title": "Implementation Guidance", "content": "- Use the `tm` structure from the standard time library to represent date and time values\n- Consider writing low-level byte read and write functions for the RTC, then wrapping them with higher-level functions used outside of `mytime.c`\n- Use the provided `bcdToDec` and `decToBcd` helper functions when reading from or writing to RTC registers\n- Carefully study the PCF8563 datasheet to understand register layout, bit masking, and valid value ranges\n\n```c\n// mytime.h\n#ifndef MYTIME_H\n#define MYTIME_H\n\n#include <time.h>\n#include <stdbool.h>\n\nbool rtc_init(void);\nbool rtc_set_time(struct tm *time);\nbool rtc_get_time(struct tm *time);\n\n#endif\n```\n\n```c\n// mytime.c\n#include \"mytime.h\"\n#include \"driver/i2c.h\"\n\n#define PCF8563_ADDR 0x51\n#define PCF8563_SECONDS_REG 0x02\n\nstatic uint8_t bcdToDec(uint8_t bcd) {\n    return ((bcd >> 4) * 10) + (bcd & 0x0F);\n}\n\nstatic uint8_t decToBcd(uint8_t dec) {\n    return ((dec / 10) << 4) | (dec % 10);\n}\n\nbool rtc_get_time(struct tm *time) {\n    uint8_t data[7];\n    // Read 7 bytes starting from seconds register\n    if (i2c_read(PCF8563_ADDR, PCF8563_SECONDS_REG, data, 7) != ESP_OK) {\n        return false;\n    }\n    \n    time->tm_sec = bcdToDec(data[0] & 0x7F);\n    time->tm_min = bcdToDec(data[1] & 0x7F);\n    time->tm_hour = bcdToDec(data[2] & 0x3F);\n    time->tm_mday = bcdToDec(data[3] & 0x3F);\n    time->tm_mon = bcdToDec(data[5] & 0x1F) - 1;\n    time->tm_year = bcdToDec(data[6]) + 100;\n    \n    return true;\n}\n```"}, {"title": "Required Files", "content": "- `mytime.h` - Header file with RTC function declarations\n- `mytime.c` - Implementation of RTC communication and time conversion logic"}], "key_points": ["Use tm structure for date/time representation", "Apply bit masks when reading RTC registers", "Use BCD conversion functions for RTC data", "Study PCF8563 datasheet for register layout"], "resources": []}' WHERE id = 'lesson-2-task1';

-- lesson-2-task2: Task 2: Wi-Fi Time Synchronization
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Attempt to connect to a Wi-Fi network during system boot and retrieve the current time if a connection is successfully established."}, {"title": "Requirements", "content": "Use the `WiFi.h` library to initialize the Wi-Fi subsystem and connect to a known network. Once connected, synchronize the system time using the Network Time Protocol."}, {"title": "Implementation Guidance", "content": "- Initialize Wi-Fi and attempt a connection during startup\n- After connecting, call `syncTimeWithNTP()` followed by `getLocalTime(&time)` to retrieve the current time\n- If Wi-Fi is unavailable, the system should continue operating using the RTC\n\n```cpp\n#include <WiFi.h>\n#include <time.h>\n\nconst char* ssid = \"YourNetwork\";\nconst char* password = \"YourPassword\";\nconst char* ntpServer = \"pool.ntp.org\";\n\nbool connectAndSyncTime() {\n    WiFi.begin(ssid, password);\n    \n    int attempts = 0;\n    while (WiFi.status() != WL_CONNECTED && attempts < 20) {\n        delay(500);\n        attempts++;\n    }\n    \n    if (WiFi.status() != WL_CONNECTED) {\n        return false;  // Continue with RTC time\n    }\n    \n    // Configure NTP\n    configTime(gmtOffset_sec, daylightOffset_sec, ntpServer);\n    \n    struct tm timeinfo;\n    if (getLocalTime(&timeinfo)) {\n        // Update RTC with NTP time\n        rtc_set_time(&timeinfo);\n        return true;\n    }\n    \n    return false;\n}\n```\n\n**Note:** The ESP32 supports only 2.4 GHz Wi-Fi networks. If a 2.4 GHz network is not available, a personal hotspot can be used instead."}, {"title": "Required Files", "content": "- `mywifi.h` and `mywifi.cpp` - Handles Wi-Fi initialization and time synchronization"}], "key_points": ["Attempt Wi-Fi connection during startup", "Use NTP to synchronize time", "Fall back to RTC if Wi-Fi unavailable", "ESP32 only supports 2.4 GHz networks"], "resources": []}' WHERE id = 'lesson-2-task2';

-- lesson-2-task3: Task 3: Time Display Formatting
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Display the current time and date on the screen in a readable format."}, {"title": "Requirements", "content": "- Time must be shown in HH:MM format using military time (24-hour format)\n- Date must be shown in MM DD YYYY format\n- The display should not update continuously\n- Design your system so the screen refreshes only once every 40 seconds"}, {"title": "Implementation Guidance", "content": "- Use `snprintf` to format time and date strings before sending them to the display\n- Ensure display updates are non-blocking and do not interfere with other system tasks\n- Integrate this logic cleanly with your existing display driver\n\n```cpp\nvoid updateTimeDisplay() {\n    struct tm timeinfo;\n    rtc_get_time(&timeinfo);\n    \n    char timeStr[16];\n    char dateStr[16];\n    \n    // Format time as HH:MM\n    snprintf(timeStr, sizeof(timeStr), \"%02d:%02d\", \n             timeinfo.tm_hour, timeinfo.tm_min);\n    \n    // Format date as MM DD YYYY\n    snprintf(dateStr, sizeof(dateStr), \"%02d %02d %04d\",\n             timeinfo.tm_mon + 1, timeinfo.tm_mday, \n             timeinfo.tm_year + 1900);\n    \n    // Display on screen\n    tft.setTextSize(4);\n    tft.setCursor(50, 80);\n    tft.println(timeStr);\n    \n    tft.setTextSize(2);\n    tft.setCursor(40, 140);\n    tft.println(dateStr);\n}\n```\n\n**Non-blocking Update Pattern:**\n```cpp\nunsigned long lastDisplayUpdate = 0;\nconst unsigned long DISPLAY_INTERVAL = 40000;  // 40 seconds\n\nvoid loop() {\n    if (millis() - lastDisplayUpdate >= DISPLAY_INTERVAL) {\n        lastDisplayUpdate = millis();\n        updateTimeDisplay();\n    }\n    // Other tasks continue running\n}\n```"}, {"title": "Required Files", "content": "- `display.h` and `display.cpp` - Handles rendering time and date on the screen\n- Integrate with existing `mytime` and `mywifi` modules"}], "key_points": ["Use snprintf for string formatting", "Update display every 40 seconds (non-blocking)", "24-hour time format (HH:MM)", "Date format: MM DD YYYY"], "resources": []}' WHERE id = 'lesson-2-task3';

-- ============================================================================
-- MODULE 3: Touch and Sensors
-- ============================================================================

-- lesson-3-task1: Task 1: Touch Coordinate Extraction
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Create a program that prints the x and y coordinates of the user''s touch on the smartwatch display."}, {"title": "Requirements", "content": "You will implement a low-level C driver to communicate with the FT6236U touch controller and extract touch coordinates over I2C. Your driver functions should be written in a dedicated source and header file, and the touch handling logic should be integrated into `main.cpp`.\n\nTouch events must be detected using a hardware interrupt so that coordinates are updated only when the screen is actively touched."}, {"title": "Implementation Guidance", "content": "- The FT6236U uses an I2C address of `0x38`, which is not explicitly listed in the datasheet\n- Use an interrupt-driven approach to detect touch events\n- Keep interrupt handlers minimal and defer coordinate processing to normal application code\n- Ensure x and y coordinates are correctly parsed from the device registers\n\n```c\n// touch.h\n#ifndef TOUCH_H\n#define TOUCH_H\n\n#include <stdbool.h>\n#include <stdint.h>\n\nbool touch_init(void);\nbool touch_read(uint16_t *x, uint16_t *y);\n\n#endif\n```\n\n```c\n// touch.c\n#include \"touch.h\"\n#include \"driver/i2c.h\"\n\n#define FT6236_ADDR 0x38\n#define FT6236_TOUCH_REG 0x03\n\nbool touch_read(uint16_t *x, uint16_t *y) {\n    uint8_t data[4];\n    \n    if (i2c_read(FT6236_ADDR, FT6236_TOUCH_REG, data, 4) != ESP_OK) {\n        return false;\n    }\n    \n    *x = ((data[0] & 0x0F) << 8) | data[1];\n    *y = ((data[2] & 0x0F) << 8) | data[3];\n    \n    return true;\n}\n```\n\n**Interrupt-Driven Approach:**\n```cpp\n#define TOUCH_INT_PIN 38\nvolatile bool touchInterrupt = false;\n\nvoid IRAM_ATTR touchISR() {\n    touchInterrupt = true;\n}\n\nvoid setup() {\n    pinMode(TOUCH_INT_PIN, INPUT);\n    attachInterrupt(digitalPinToInterrupt(TOUCH_INT_PIN), touchISR, FALLING);\n}\n\nvoid loop() {\n    if (touchInterrupt) {\n        touchInterrupt = false;\n        uint16_t x, y;\n        if (touch_read(&x, &y)) {\n            Serial.printf(\"Touch: x=%d, y=%d\\n\", x, y);\n        }\n    }\n}\n```"}, {"title": "Required Files", "content": "- `touch.h` and `touch.c` - Handles FT6236U communication and coordinate extraction"}], "key_points": ["FT6236U I2C address is 0x38", "Use interrupt-driven touch detection", "Parse coordinates from 4-byte register read", "Keep ISR minimal - set flag only"], "resources": []}' WHERE id = 'lesson-3-task1';

-- lesson-3-task2: Task 2: Step Count Screen
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Create a screen that displays the total step count stored in the BMA423 accelerometer."}, {"title": "Requirements", "content": "This screen must initialize the accelerometer, retrieve the stored step count, and display it in a readable format. All accelerometer-related functionality should be implemented using the `Accel` class within `accel.h` and `accel.cpp`. The screen logic should then be driven from `main.cpp`."}, {"title": "Implementation Guidance", "content": "- Initialize the BMA423 before attempting to read step data\n- Use the provided accelerometer abstraction rather than accessing registers directly\n- Ensure the displayed step count reflects the value stored in the sensor\n\n```cpp\n// accel.h\n#ifndef ACCEL_H\n#define ACCEL_H\n\nclass Accel {\npublic:\n    bool init();\n    uint32_t getStepCount();\n    void resetStepCount();\n    \nprivate:\n    bool initialized;\n};\n\n#endif\n```\n\n```cpp\n// accel.cpp\n#include \"accel.h\"\n#include <BMA423.h>\n\nBMA423 bma;\n\nbool Accel::init() {\n    if (bma.begin()) {\n        bma.enableStepCounter();\n        initialized = true;\n        return true;\n    }\n    return false;\n}\n\nuint32_t Accel::getStepCount() {\n    if (!initialized) return 0;\n    return bma.getStepCount();\n}\n```\n\n**Display Integration:**\n```cpp\nvoid drawStepScreen() {\n    tft.fillScreen(TFT_BLACK);\n    \n    // Draw step icon\n    // ...\n    \n    // Display step count\n    uint32_t steps = accel.getStepCount();\n    char stepStr[16];\n    snprintf(stepStr, sizeof(stepStr), \"%lu\", steps);\n    \n    tft.setTextSize(4);\n    tft.setTextColor(TFT_WHITE);\n    tft.setCursor(80, 100);\n    tft.println(stepStr);\n    \n    tft.setTextSize(2);\n    tft.setCursor(90, 150);\n    tft.println(\"steps\");\n}\n```"}, {"title": "Required Files", "content": "- `accel.h` and `accel.cpp` - Handles BMA423 initialization and step count retrieval"}], "key_points": ["Initialize BMA423 before reading data", "Use accelerometer abstraction class", "Enable step counter feature", "Display formatted step count"], "resources": []}' WHERE id = 'lesson-3-task2';

-- lesson-3-task3: Task 3: Wi-Fi Status Screen
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Create a screen that displays the current Wi-Fi connection status of the smartwatch."}, {"title": "Requirements", "content": "The screen must support three states:\n- **Wi-Fi Connected** - Display the network SSID\n- **Wi-Fi Connecting** - Show connection in progress\n- **Wi-Fi Not Connected** - Indicate no connection\n\nYou must also implement a button that allows the user to manually attempt to reconnect to the Wi-Fi network.\n\nAll Wi-Fi related functionality should be implemented in `mywifi.h` and `mywifi.cpp` using the `MyWiFi` class, with high-level control handled in `main.cpp`."}, {"title": "Implementation Guidance", "content": "- Track Wi-Fi state internally and update the screen accordingly\n- Use the provided `drawWiFiSymbol` and `drawRefreshSymbol` helper functions to display icons\n- Ensure screen updates are responsive but not excessively frequent\n\n```cpp\n// mywifi.h\nenum WiFiState {\n    WIFI_DISCONNECTED,\n    WIFI_CONNECTING,\n    WIFI_CONNECTED\n};\n\nclass MyWiFi {\npublic:\n    void init();\n    void connect();\n    void disconnect();\n    WiFiState getState();\n    String getSSID();\n    \nprivate:\n    WiFiState state;\n};\n```\n\n**Screen Drawing:**\n```cpp\nvoid drawWiFiScreen() {\n    tft.fillScreen(TFT_BLACK);\n    \n    // Draw Wi-Fi symbol\n    drawWiFiSymbol(100, 50, wifi.getState() == WIFI_CONNECTED);\n    \n    // Display status text\n    tft.setTextSize(2);\n    tft.setCursor(40, 120);\n    \n    switch (wifi.getState()) {\n        case WIFI_CONNECTED:\n            tft.setTextColor(TFT_GREEN);\n            tft.println(\"Connected\");\n            tft.setCursor(40, 150);\n            tft.println(wifi.getSSID());\n            break;\n            \n        case WIFI_CONNECTING:\n            tft.setTextColor(TFT_YELLOW);\n            tft.println(\"Connecting...\");\n            break;\n            \n        case WIFI_DISCONNECTED:\n            tft.setTextColor(TFT_RED);\n            tft.println(\"Not Connected\");\n            break;\n    }\n    \n    // Draw refresh button\n    drawRefreshSymbol(100, 200);\n}\n```"}, {"title": "Required Files", "content": "- `mywifi.h` and `mywifi.cpp` - Handles Wi-Fi state management and reconnection logic\n- `display.h` and `display.cpp` - Handles rendering of all screens and symbols"}], "key_points": ["Track three Wi-Fi states", "Display SSID when connected", "Provide manual reconnect button", "Use helper functions for icons"], "resources": []}' WHERE id = 'lesson-3-task3';

-- ============================================================================
-- MODULE 4: Integration
