-- lesson-4-task1: Task 1: Stopwatch Screen
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Create a stopwatch screen that supports start, stop, and reset functionality."}, {"title": "Requirements", "content": "The stopwatch must display time in HH:MM:SS format and continue running even when the stopwatch screen is not actively displayed. This requires separating stopwatch timing logic from display rendering logic."}, {"title": "Implementation Guidance", "content": "- Use semaphores to safely coordinate access to the display whenever screen content changes\n- Ensure the stopwatch state persists independently of the active screen\n- Avoid resetting or pausing the stopwatch when navigating between screens\n\n```cpp\nstruct Stopwatch {\n    bool running;\n    unsigned long startTime;\n    unsigned long elapsedTime;\n};\n\nStopwatch stopwatch = {false, 0, 0};\n\nvoid startStopwatch() {\n    if (!stopwatch.running) {\n        stopwatch.startTime = millis() - stopwatch.elapsedTime;\n        stopwatch.running = true;\n    }\n}\n\nvoid stopStopwatch() {\n    if (stopwatch.running) {\n        stopwatch.elapsedTime = millis() - stopwatch.startTime;\n        stopwatch.running = false;\n    }\n}\n\nvoid resetStopwatch() {\n    stopwatch.running = false;\n    stopwatch.elapsedTime = 0;\n}\n\nunsigned long getStopwatchTime() {\n    if (stopwatch.running) {\n        return millis() - stopwatch.startTime;\n    }\n    return stopwatch.elapsedTime;\n}\n```\n\n**Display Formatting:**\n```cpp\nvoid drawStopwatchScreen() {\n    unsigned long ms = getStopwatchTime();\n    int hours = ms / 3600000;\n    int minutes = (ms % 3600000) / 60000;\n    int seconds = (ms % 60000) / 1000;\n    \n    char timeStr[16];\n    snprintf(timeStr, sizeof(timeStr), \"%02d:%02d:%02d\", \n             hours, minutes, seconds);\n    \n    tft.setTextSize(3);\n    tft.setCursor(40, 100);\n    tft.println(timeStr);\n    \n    // Draw control buttons\n    drawStartStopButton(stopwatch.running);\n    drawResetButton();\n}\n```"}, {"title": "Required Files", "content": "- Integrate stopwatch logic with existing display and navigation modules"}], "key_points": ["Separate timing logic from display rendering", "Stopwatch runs independently of active screen", "Use HH:MM:SS format", "Provide start, stop, reset controls"], "resources": []}' WHERE id = 'lesson-4-task1';

-- lesson-4-task2: Task 2: Screen Navigation
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Design and implement touch buttons that allow the user to navigate between all previously created screens."}, {"title": "Requirements", "content": "You must support navigation between:\n- Home screen\n- Step count screen\n- Wi-Fi screen\n- Stopwatch screen\n\nButton interactions should be responsive and consistent across screens."}, {"title": "Implementation Guidance", "content": "- Centralize screen state management to avoid duplicated logic\n- Use touch events to trigger screen transitions rather than polling\n- Ensure only one screen is active at a time\n\n```cpp\nenum Screen {\n    SCREEN_HOME,\n    SCREEN_STEPS,\n    SCREEN_WIFI,\n    SCREEN_STOPWATCH\n};\n\nScreen currentScreen = SCREEN_HOME;\n\nvoid handleNavigation(uint16_t x, uint16_t y) {\n    // Check for navigation button touch\n    if (isLeftButton(x, y)) {\n        navigatePrevious();\n    } else if (isRightButton(x, y)) {\n        navigateNext();\n    }\n}\n\nvoid navigateNext() {\n    switch (currentScreen) {\n        case SCREEN_HOME:\n            currentScreen = SCREEN_STEPS;\n            break;\n        case SCREEN_STEPS:\n            currentScreen = SCREEN_WIFI;\n            break;\n        case SCREEN_WIFI:\n            currentScreen = SCREEN_STOPWATCH;\n            break;\n        case SCREEN_STOPWATCH:\n            currentScreen = SCREEN_HOME;\n            break;\n    }\n    updateDisplay();\n}\n\nvoid updateDisplay() {\n    switch (currentScreen) {\n        case SCREEN_HOME:\n            drawHomeScreen();\n            break;\n        case SCREEN_STEPS:\n            drawStepScreen();\n            break;\n        case SCREEN_WIFI:\n            drawWiFiScreen();\n            break;\n        case SCREEN_STOPWATCH:\n            drawStopwatchScreen();\n            break;\n    }\n}\n```"}, {"title": "Required Files", "content": "- Integrate navigation logic with existing display, touch, and screen modules"}], "key_points": ["Centralize screen state management", "Use touch events for navigation", "Only one screen active at a time", "Consistent button behavior across screens"], "resources": []}' WHERE id = 'lesson-4-task2';

-- lesson-4-task3: Task 3: Battery Display
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Use the power management system to display the current battery percentage on the home screen."}, {"title": "Requirements", "content": "You must read battery data using the AXP20X library and display the value using the provided `drawBatterySymbol` function. The battery percentage should update dynamically and reflect real system state."}, {"title": "Implementation Guidance", "content": "- Retrieve battery information through the AXP20X driver\n- Pass the battery percentage value into the display drawing function\n- Ensure battery updates do not interfere with other display operations\n\n```cpp\nint getBatteryPercentage() {\n    if (axp.isBatteryConnect()) {\n        return axp.getBattPercentage();\n    }\n    return -1;  // No battery connected\n}\n\nvoid drawBatterySymbol(int x, int y, int percentage) {\n    // Draw battery outline\n    tft.drawRect(x, y, 30, 15, TFT_WHITE);\n    tft.fillRect(x + 30, y + 4, 3, 7, TFT_WHITE);\n    \n    // Calculate fill width\n    int fillWidth = (percentage * 26) / 100;\n    \n    // Choose color based on percentage\n    uint16_t color;\n    if (percentage > 50) {\n        color = TFT_GREEN;\n    } else if (percentage > 20) {\n        color = TFT_YELLOW;\n    } else {\n        color = TFT_RED;\n    }\n    \n    // Fill battery\n    tft.fillRect(x + 2, y + 2, fillWidth, 11, color);\n}\n\nvoid drawHomeScreen() {\n    // ... other home screen content ...\n    \n    // Draw battery in top-right corner\n    int battery = getBatteryPercentage();\n    if (battery >= 0) {\n        drawBatterySymbol(200, 5, battery);\n        \n        // Optional: show percentage text\n        char battStr[8];\n        snprintf(battStr, sizeof(battStr), \"%d%%\", battery);\n        tft.setCursor(165, 7);\n        tft.setTextSize(1);\n        tft.println(battStr);\n    }\n}\n```"}, {"title": "Required Files", "content": "- `power.h` and `power.cpp` - Battery reading functionality\n- `display.h` and `display.cpp` - Battery symbol rendering"}], "key_points": ["Use AXP20X for battery percentage", "Color-code battery level", "Update without blocking other operations", "Handle case when battery not connected"], "resources": []}' WHERE id = 'lesson-4-task3';

-- lesson-4-task4: Task 4: RTOS Architecture
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Structure the firmware using a real-time operating system to handle multiple subsystems concurrently."}, {"title": "Requirements", "content": "You should create tasks strategically to manage:\n- Display updates\n- Input handling\n- Timekeeping\n- Sensor polling\n- Networking\n\nTasks must be designed to operate reliably without blocking one another."}, {"title": "Implementation Guidance", "content": "- Assign appropriate priorities to tasks based on timing sensitivity\n- Use semaphores or task notifications for safe communication between tasks\n- Keep interrupt service routines minimal and defer processing to tasks\n\n```cpp\n// Task handles\nTaskHandle_t displayTaskHandle;\nTaskHandle_t sensorTaskHandle;\nTaskHandle_t inputTaskHandle;\n\n// Semaphore for display access\nSemaphoreHandle_t displayMutex;\n\nvoid displayTask(void *parameter) {\n    while (1) {\n        if (xSemaphoreTake(displayMutex, portMAX_DELAY)) {\n            updateDisplay();\n            xSemaphoreGive(displayMutex);\n        }\n        vTaskDelay(pdMS_TO_TICKS(100));\n    }\n}\n\nvoid sensorTask(void *parameter) {\n    while (1) {\n        readAccelerometer();\n        updateStepCount();\n        vTaskDelay(pdMS_TO_TICKS(50));\n    }\n}\n\nvoid inputTask(void *parameter) {\n    while (1) {\n        if (touchInterrupt) {\n            touchInterrupt = false;\n            handleTouch();\n        }\n        if (buttonInterrupt) {\n            buttonInterrupt = false;\n            handleButton();\n        }\n        vTaskDelay(pdMS_TO_TICKS(10));\n    }\n}\n\nvoid setup() {\n    displayMutex = xSemaphoreCreateMutex();\n    \n    xTaskCreate(displayTask, \"Display\", 4096, NULL, 1, &displayTaskHandle);\n    xTaskCreate(sensorTask, \"Sensor\", 2048, NULL, 2, &sensorTaskHandle);\n    xTaskCreate(inputTask, \"Input\", 2048, NULL, 3, &inputTaskHandle);\n}\n```\n\n**Priority Guidelines:**\n- Input handling: High priority (3) - responsive to user\n- Sensor polling: Medium priority (2) - regular updates\n- Display updates: Low priority (1) - can be delayed slightly"}, {"title": "Required Files", "content": "- Task coordination and system initialization in `main.cpp`\n- All functionality should integrate with existing modules"}], "key_points": ["Create separate tasks for each subsystem", "Use mutex for shared resource protection", "Assign priorities based on timing needs", "Keep ISRs minimal - defer to tasks"], "resources": []}' WHERE id = 'lesson-4-task4';

-- ============================================================================
-- MODULE 5: Design Challenge
-- ============================================================================

-- lesson-5-overview: Short Circuit Design Challenge
UPDATE lessons SET content_json = '{"sections": [{"title": "About the Design Challenge", "content": "The Short Circuit Design Challenge is our way of recognizing exceptional engineering work. While our project kits establish a strong technical foundation, this challenge is designed for students who extend that foundation through innovation, thoughtful design, and rigorous execution.\n\nParticipants are encouraged to move beyond baseline functionality and demonstrate how engineering decisions, system architecture, and creativity come together in a cohesive final product."}, {"title": "Awards and Recognition", "content": "**Cash Prizes:**\n- First Place: $1,000\n- Second Place: $750\n- Third Place: $500\n\n**Website Recognition:**\nWinning projects will be featured on the Short Circuit website and highlighted with a project demonstration and a short contributor profile. This public recognition can be shared with recruiters, academic programs, and professional networks.\n\n**Certificate of Achievement:**\nRecipients will earn a verified Certificate of Achievement acknowledging design excellence. This credential may be displayed on professional platforms such as LinkedIn or included in portfolios and resumes.\n\n**Exclusive Opportunities:**\nWinners will receive a complimentary future project kit and gain access to a private mentorship and career opportunities group, providing continued engagement with engineers, founders, and industry professionals."}, {"title": "Project Extension Opportunities", "content": "To participate in the Design Challenge, students must meaningfully extend the baseline smartwatch project. The examples below illustrate possible directions for expansion:\n\n**System Architecture and Software Design:**\n- Develop a desktop, web, or mobile dashboard to visualize live smartwatch data\n- Design a companion application for monitoring activity, battery status, or time statistics\n- Implement firmware update mechanisms or modular feature expansion\n\n**Power Management and Performance Optimization:**\n- Design adaptive power management strategies based on user behavior\n- Implement advanced sleep and wake mechanisms to extend battery life\n- Analyze and visualize power consumption across system components\n\n**Health, Motion, and Activity Analysis:**\n- Implement step counting, calorie estimation, and activity classification algorithms\n- Create daily, weekly, or long-term activity summaries\n- Detect and classify motion patterns using accelerometer data\n\n**User Interface and User Experience:**\n- Design custom watch faces or interactive display layouts\n- Implement gesture-based navigation or animated transitions\n- Improve usability through thoughtful visual hierarchy and interaction design\n\n**Networking, Data, and Cloud Integration:**\n- Synchronize data with cloud services or external databases\n- Develop analytics tools for long-term data tracking\n- Implement secure data transfer and authentication mechanisms\n\n**Creative and Experimental Extensions:**\n- Design productivity tools such as timers or focus modes\n- Create adaptive alarms or notifications based on sensor input\n- Integrate additional peripherals or explore novel interaction concepts\n\nThe examples provided are starting points. The strongest projects often explore ideas beyond those listed here."}, {"title": "Eligibility", "content": "You must be an active university student to enter the design challenge. You will need to provide a university email to get consideration.\n\nWe invite you to apply the concepts and techniques developed throughout this program to create a project that reflects your approach to engineering problem solving. We look forward to reviewing your work and recognizing outstanding contributions through the Short Circuit Design Challenge."}], "key_points": ["Cash prizes: $1000, $750, $500", "Featured on Short Circuit website", "Certificate of Achievement", "Must meaningfully extend baseline project", "University students only"], "resources": []}' WHERE id = 'lesson-5-overview';
